-- =====================================================================
-- Mock data seed v2 — 兩災害情境 (2026-06 spec) ;PR12-ready
-- =====================================================================
-- Scenario A | 花蓮光復泥石流 2024-07-24:站16(分項為準)/users27(志工20+NGO4+官方3)/tickets30(rescue5,hr10,supply8,無7)
-- Scenario B | 宜蘭冬山水災   2025-10-03:站9 /users10(志工4+NGO5+官方1)/tickets8(rescue2,hr3,supply2,無1)
-- 每張 ticket 1–2 個 task;hr task 帶志工認領 (task_assignments)。聯絡欄位混用電話與 LINE ID。
--
-- PR12-ready:tickets.disaster_type / task_assignments.status 用條件式 DO 區塊,
--   欄位存在才寫入 → 部署 PR#11/#12 前後跑同一檔案皆可。
-- UUID 前綴:users=c…、A站=a…、B站=b…、tickets=d…、tasks=e…、assignments=f… (可重跑自清)
-- 登入:全部 37 人,密碼 Mock1234!(salt_frontend=mockdata12345678;
--   API password=sha256('Mock1234!'+salt)=3a88d3527a01c374689c19033f45ecfad25a749ade957b3044591ad30551e79a)
-- Run (local dev):  psql "host=127.0.0.1 port=5432 user=postgres dbname=postgres" \
--                     -f scripts/seed_mock_scenarios.sql
-- Run (staging VM): docker compose -f docker-compose.staging.yml exec -T db \
--                     psql -U postgres -d postgres -v ON_ERROR_STOP=1 < scripts/seed_mock_scenarios.sql
--                   (ON_ERROR_STOP=1 is required: without it psql exits 0 on mid-file errors.)
-- =====================================================================

BEGIN;

-- 0. 清除既有 seed(依前綴,可重跑)
DELETE FROM task_assignments WHERE uuid::text LIKE 'f0000000-%' OR task_uuid::text LIKE 'e0000000-%';
DELETE FROM task_properties WHERE task_uuid::text LIKE 'e0000000-%';
DELETE FROM ticket_tasks WHERE uuid::text LIKE 'e0000000-%';
DELETE FROM tickets WHERE uuid::text LIKE 'd0000000-%';
DELETE FROM crowd_sourcing WHERE station_uuid::text LIKE 'a0000000-%' OR station_uuid::text LIKE 'b0000000-%';
DELETE FROM station_properties WHERE station_uuid::text LIKE 'a0000000-%' OR station_uuid::text LIKE 'b0000000-%';
DELETE FROM stations WHERE uuid::text LIKE 'a0000000-%' OR uuid::text LIKE 'b0000000-%';
DELETE FROM base_geometries WHERE uuid::text LIKE 'a0000000-%' OR uuid::text LIKE 'b0000000-%' OR uuid::text LIKE 'd0000000-%';
DELETE FROM user_group_assign WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM user_identities WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM user_contacts WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM users WHERE uuid::text LIKE 'c0000000-%';

-- 1. USERS — 37 人(A:志工20+NGO4+官方3;B:志工4+NGO5+官方1)

-- 1b. 登入憑證(email+密碼 Mock1234!+Login User 群組)
SELECT gen_random_uuid(), u.uuid, 'password', NULL, 'pbkdf2_sha256$600000$mockdata12345678$22c5f18b05a3da2d9b73ce908b1b0209$2e9aa846631acac187bcd7c2373fe94702ff7d57fdd1af73a7f258dea4c11a4d', now()
FROM users u WHERE u.uuid::text LIKE 'c0000000-%';
SELECT gen_random_uuid(), u.uuid, (SELECT uuid FROM groups WHERE name='Login User')
FROM users u WHERE u.uuid::text LIKE 'c0000000-%';

-- 2. STATIONS — base_geometries + stations + EAV + 投票



-- 投票 (crowd_sourcing) — 無自評、credibility 與 user 一致

-- 3. TICKETS — A:30 / B:8(聯絡欄位混用電話與 LINE ID;無類型 ticket 的 task_type 為 NULL)


-- 4. TASKS — 每張 ticket 1–2 個(hr 帶志工認領)



-- 5. PR12-ready 條件區塊 — 欄位存在才寫(部署 PR#11/#12 後重跑即生效)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_name='tickets' AND column_name='disaster_type') THEN
    UPDATE tickets SET disaster_type='mudslide'
     WHERE uuid::text LIKE 'd0000000-%' AND right(uuid::text,12)::bigint <= 30;
    UPDATE tickets SET disaster_type='flood'
     WHERE uuid::text LIKE 'd0000000-%' AND right(uuid::text,12)::bigint > 30;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_name='task_assignments' AND column_name='status') THEN
    UPDATE task_assignments SET status = (ARRAY['accepted','en_route','completed'])
      [1 + (right(uuid::text,12)::bigint % 3)]
     WHERE uuid::text LIKE 'f0000000-%';
  END IF;
END $$;

COMMIT;
